package com.example.kafkastreaming.service;

import com.example.kafkastreaming.config.KafkaConfig;
import com.example.kafkastreaming.model.EventMessage;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.kafka.support.KafkaHeaders;
import org.springframework.messaging.support.MessageBuilder;
import org.springframework.stereotype.Service;

import java.util.UUID;

@Service
public class EventPublisher {

    private final KafkaTemplate<String, Object> kafkaTemplate;

    public EventPublisher(KafkaTemplate<String, Object> kafkaTemplate) {
        this.kafkaTemplate = kafkaTemplate;
    }

    public void publish(EventMessage event) {
        String key = event.getEventId() != null ? event.getEventId() : UUID.randomUUID().toString();
        if (event.getEventId() == null) {
            event.setEventId(key);
        }

        kafkaTemplate.send(
                MessageBuilder.withPayload(event)
                        .setHeader(KafkaHeaders.TOPIC, KafkaConfig.TOPIC_EVENTS)
                        .setHeader(KafkaHeaders.MESSAGE_KEY, key)
                        .build()
        );
    }
}

package com.example.kafkastreaming.consumer;

import com.example.kafkastreaming.config.KafkaConfig;
import com.example.kafkastreaming.model.EventMessage;
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.kafka.support.Acknowledgment;
import org.springframework.stereotype.Component;

@Component
public class EventConsumer {

    private static final Logger log = LoggerFactory.getLogger(EventConsumer.class);

    @KafkaListener(
            topics = KafkaConfig.TOPIC_EVENTS,
            groupId = "event-streaming-platform",
            containerFactory = "kafkaListenerContainerFactory"
    )
    public void onMessage(ConsumerRecord<String, EventMessage> record, Acknowledgment ack) {
        try {
            EventMessage event = record.value();
            log.info("Consumed event: key={}, partition={}, offset={}, type={}, id={}",
                    record.key(), record.partition(), record.offset(),
                    event != null ? event.getEventType() : null,
                    event != null ? event.getEventId() : null
            );
            ack.acknowledge();
        } catch (Exception e) {
            log.error("Failed processing record: key={}, partition={}, offset={}", record.key(), record.partition(), record.offset(), e);
            throw e;
        }
    }
}

package com.example.kafkastreaming.web;

import com.example.kafkastreaming.model.EventMessage;
import com.example.kafkastreaming.service.EventPublisher;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.time.Instant;
import java.util.Map;
import java.util.UUID;

@RestController
@RequestMapping("/api/events")
public class EventController {

    private final EventPublisher publisher;

    public EventController(EventPublisher publisher) {
        this.publisher = publisher;
    }

    @PostMapping
    public ResponseEntity<EventMessage> publish(@RequestBody Map<String, Object> payload,
                                               @RequestParam(defaultValue = "generic.event") String eventType) {
        EventMessage event = new EventMessage(
                UUID.randomUUID().toString(),
                eventType,
                Instant.now(),
                payload
        );
        publisher.publish(event);
        return ResponseEntity.accepted().body(event);
    }
}

